      "path": "src/csv.ts",
      "content": "declare const require: any;
declare const process: any;
const fs = require('node:fs');

class CsvParser {
  private delimiter: string;

  constructor(options?: { delimiter?: string }) {
    this.delimiter = options?.delimiter ?? ',';
  }

  parse(text: string): Record<string, string>[] {
    const rows = text.split('\n').filter(row => row.trim() !== '');
    if (rows.length === 0) return [];

    const headers = rows[0].split(this.delimiter);
    const result: Record<string, string>[] = [];

    for (let i = 1; i < rows.length; i++) {
      const row = rows[i];
      const values = this.parseRow(row);
      const record: Record<string, string> = {};

      headers.forEach((header, index) => {
        record[header] = values[index];
      });

      result.push(record);
    }

    return result;
  }

  private parseRow(row: string): string[] {
    const values: string[] = [];
    let value = '';
    let inQuotes = false;

    for (let i = 0; i < row.length; i++) {
      const char = row[i];

      if (char === '"') {
        if (i > 0 && row[i - 1] === '"') {
          value += '"'; // Unescaped quote
          i++; // Skip the next character as it's part of the escaped quote
        } else {
          inQuotes = !inQuotes;
        }
      } else if (char === this.delimiter && !inQuotes) {
        values.push(value);
        value = '';
      } else {
        value += char;
      }
    }

    values.push(value); // Add the last value
    return values;
  }

  stringify(rows: Record<string, string>[]): string {
    if (rows.length === 0) return '';

    const headers = Object.keys(rows[0]);
    const result: string[] = [headers.join(this.delimiter)];

    for (const row of rows) {
      const values = headers.map(header => this.stringifyValue(row[header]));
      result.push(values.join(this.delimiter));
    }

    return result.join('\n');
  }

  private stringifyValue(value: string): string {
    if (value.includes('"') || value.includes(this.delimiter)) {
      return `"${value.replace(/"/g, '""')}"`;
    }
    return value;
  }
}

export class CsvFilter {
  private rows: Record<string, string>[];

  constructor(rows: Record<string, string>[]) {
    this.rows = rows;
  }

  where(predicate: (row: Record<string, string>) => boolean): CsvFilter {
    const filteredRows = this.rows.filter(predicate);
    return new CsvFilter(filteredRows);
  }

  select(columns: string[]): CsvFilter {
    const selectedRows = this.rows.map(row => {
      const selectedRow: Record<string, string> = {};
      for (const column of columns) {
        if (row.hasOwnProperty(column)) {
          selectedRow[column] = row[column];
        }
      }
      return selectedRow;
    });

    return new CsvFilter(selectedRows);
  }

  sortBy(column: string): CsvFilter {
    const sortedRows = [...this.rows].sort((a, b) => {
      if (a[column] < b[column]) return -1;
      if (a[column] > b[column]) return 1;
      return 0;
    });

    return new CsvFilter(sortedRows);
  }

  count(): number {
    return this.rows.length;
  }
}
